type Action =
  | { variant: 'link'; href: string; onClick?: never }
  | { variant: 'button'; onClick: () => void; href?: never };

function ActionItem({ variant, label, ...props }: Action & { label: string }) {
  if (variant === 'link') return <a href={props.href}>{label}</a>;
  return <button onClick={props.onClick}>{label}</button>;
}

// TypeScript ловит неверное использование на этапе компиляции:
// <ActionItem variant="link" onClick={() => {}} label="x" />  ← Ошибка
```

**Типичная ошибка на интервью:** Использовать `any` как выход (`const ref = useRef<any>(null)`) — это отменяет смысл TypeScript. Используйте `unknown` с сужением типов или правильный DOM-тип (`HTMLInputElement`, `HTMLDivElement`). Вторая ловушка: не указывать дженерик в хуках — `useState()` без типа по умолчанию будет `undefined`, теряя null-безопасность. Явно указывайте: `useState<User | null>(null)`.

